{
  "topic": "Applying 2D shearing transformations to shapes and using mathematical expressions to create interactive, responsive visual patterns.",
  "concepts": [
    {
      "name": "shearX() and shearY()",
      "timecode": "02:31",
      "explanation": "Functions that skew an object along the X or Y axis. The instructor explains that these functions use angles to displace points based on their distance from the origin.",
      "why_it_matters": "It allows for non-uniform distortion of shapes, creating a sense of perspective or stretching that rotation and scaling cannot achieve alone."
    },
    {
      "name": "Responsive Canvas (windowWidth/Height)",
      "timecode": "00:33",
      "explanation": "Using `windowWidth` and `windowHeight` instead of fixed numbers in `createCanvas()` so the sketch fills the entire browser window.",
      "why_it_matters": "Ensures the art looks consistent and fills the screen regardless of the user's monitor size."
    },
    {
      "name": "Centering Transformations",
      "timecode": "04:03",
      "explanation": "Using the expression `(width/2 - mouseX)` to calculate a value relative to the center of the screen rather than the edge.",
      "why_it_matters": "Without this, shearing only happens in one direction (e.g., only to the right). Centering it allows the shape to skew left or right depending on which side of the center the mouse is on."
    },
    {
      "name": "map() for Color Gradients",
      "timecode": "08:23",
      "explanation": "Using the `map()` function to take a spatial value (like an X coordinate in a loop) and translate it into a color range (0–255).",
      "why_it_matters": "It allows you to create complex, data-driven aesthetic patterns like color gradients that change based on the position of shapes."
    },
    {
      "name": "Isolating Transformations with push() and pop()",
      "timecode": "13:28",
      "explanation": "Wrapping specific transformations in `push()` and `pop()` so that the shearing or rotation only affects a specific object and doesn't 'leak" into the rest of the code.",
      "why_it_matters": "Prevents a single transformation from affecting every subsequent shape drawn in the sketch."
    }
  ],
  "code_examples": [
    {
      "timecode": "02:37",
      "language": "javascript",
      "code": "shearX(mouseX / 10);\nrectMode(CENTER);\ntranslate(width/2, height/2);\nrect(0, 0, 100, 100);",
      "demonstrates": "Basic horizontal shearing controlled by mouse movement.",
      "common_issue": "If shear is called after the shape, it won't affect that shape."
    },
    {
      "timecode": "04:12",
      "language": "javascript",
      "code": "shearX((width / 2 - mouseX) / 10);",
      "demonstrates": "Centering the shear effect so it skews symmetrically based on mouse position relative to center.",
      "common_issue": "Forgetting parentheses around the subtraction will cause the division to only apply to mouseX, leading to extreme distortion."
    },
    {
      "timecode": "16:00",
      "language": "javascript",
      "code": "if (width > height) {\n  rectLength = 0.75;\n} else {\n  rectLength = width * 0.75;\n}",
      "demonstrates": "Using conditional logic to ensure a shape stays contained within the canvas regardless of aspect ratio.",
      "common_issue": "Shapes flying off-screen when the window is resized if dimensions are hard-coded."
    }
  ],
  "mistakes_and_fixes": [
    {
      "timecode": "03:00",
      "symptom": "The shape isn't shearing/distorting.",
      "cause": "The transformation function (like `shearX`) was placed *after* the drawing command.",
      "fix": "Move the transformation function above the shape's drawing code.",
      "related_concept": "Order of operations / Transformation order"
    },
    {
      "timecode": "03:45",
      "symptom": "The shape only skews in one direction (e.g., always to the right).",
      "cause": "Using `mouseX` directly instead of calculating its distance from the center.",
      "fix": "Use an expression like `(width/2 - mouseX)` to allow for negative and positive values.",
      "related_concept": "Coordinate management"
    },
    {
      "timecode": "17:03",
      "symptom": "The code is getting too complex and confusing while trying to manage multiple variables.",
      "cause": "Trying to calculate everything in one line without structure.",
      "fix": "Use variables (like `rectLength`) and conditional logic (`if/else`) to manage dimensions.",
      "related_concept": "Control flow / Variables"
    }
  ],
